 {"id":"DIAL-jxo","title":"Event Webhooks and Script Triggers","description":"# Description

Implement event webhooks and script triggers that fire on dial events, enabling home automation integration and custom extensibility.

## Background & Rationale

### The Problem
The Surface Dial is a single-purpose device by default. Users want to:
- Trigger smart home actions (dim lights when volume > 80%)
- Log events to external systems
- Chain multiple actions together
- Integrate with automation tools (Home Assistant, IFTTT, etc.)

Currently, extending functionality requires modifying source code.

### Why This Matters
1. **Power user extensibility** — "I can make it do anything!"
2. **Home automation** — Natural fit for smart home enthusiasts
3. **No-code customization** — Scripts and webhooks need no Rust
4. **Future-proof** — Users can add features we didn't think of
5. **Debugging aid** — Log events to file for troubleshooting

### Design Decision
- Fire events on: volume change, mode change, mute toggle, device switch, click patterns
- Two trigger types: shell scripts and HTTP webhooks
- Events include full context (volume level, mode, timestamp, etc.)
- Configurable per-event-type (don't spam webhooks on every rotation)

## Implementation Details

### Event Types

```rust
// src/events/mod.rs

use serde::Serialize;
use std::time::SystemTime;

#[derive(Debug, Clone, Serialize)]
#[serde(tag = "type", rename_all = "snake_case")]
pub enum DaemonEvent {
    VolumeChange {
        old_volume: i32,
        new_volume: i32,
        mode: String,  // "volume" or "microphone"
    },
    ModeChange {
        old_mode: String,
        new_mode: String,
    },
    MuteToggle {
        muted: bool,
        mode: String,
    },
    DeviceSwitch {
        old_device: String,
        new_device: String,
    },
    Click {
        click_type: String,  // "single", "double", "triple", "long_press"
    },
    ConnectionChange {
        connected: bool,
    },
    BatteryChange {
        old_percent: Option<u8>,
        new_percent: u8,
    },
}

#[derive(Debug, Clone, Serialize)]
pub struct EventPayload {
    pub event: DaemonEvent,
    pub timestamp: String,  // ISO 8601
    pub device_id: Option<String>,
}

impl EventPayload {
    pub fn new(event: DaemonEvent) -> Self {
        Self {
            event,
            timestamp: chrono::Utc::now().to_rfc3339(),
            device_id: None,  // Set by daemon
        }
    }

    pub fn to_json(&self) -> String {
        serde_json::to_string(self).unwrap_or_default()
    }

    pub fn to_env_vars(&self) -> Vec<(String, String)> {
        // Flatten event to environment variables for shell scripts
        let mut vars = vec![
            ("DIAL_EVENT_TYPE".to_string(), self.event_type()),
            ("DIAL_TIMESTAMP".to_string(), self.timestamp.clone()),
        ];

        match &self.event {
            DaemonEvent::VolumeChange { old_volume, new_volume, mode } => {
                vars.push(("DIAL_OLD_VOLUME".to_string(), old_volume.to_string()));
                vars.push(("DIAL_NEW_VOLUME".to_string(), new_volume.to_string()));
                vars.push(("DIAL_MODE".to_string(), mode.clone()));
            }
            DaemonEvent::MuteToggle { muted, mode } => {
                vars.push(("DIAL_MUTED".to_string(), muted.to_string()));
                vars.push(("DIAL_MODE".to_string(), mode.clone()));
            }
            // ... other event types
            _ => {}
        }

        vars
    }

    fn event_type(&self) -> String {
        match &self.event {
            DaemonEvent::VolumeChange { .. } => "volume_change",
            DaemonEvent::ModeChange { .. } => "mode_change",
            DaemonEvent::MuteToggle { .. } => "mute_toggle",
            DaemonEvent::DeviceSwitch { .. } => "device_switch",
            DaemonEvent::Click { .. } => "click",
            DaemonEvent::ConnectionChange { .. } => "connection_change",
            DaemonEvent::BatteryChange { .. } => "battery_change",
        }.to_string()
    }
}
```

### Event Handler

```rust
// src/events/handler.rs

use std::process::Command;
use std::time::{Duration, Instant};
use tokio::time::timeout;

pub struct EventHandler {
    config: EventConfig,
    last_volume_event: Option<Instant>,
    http_client: reqwest::Client,
}

#[derive(Debug, Clone, serde::Deserialize)]
pub struct EventConfig {
    pub enabled: bool,
    pub debounce_ms: u64,  // For volume changes
    pub scripts: Vec<ScriptTrigger>,
    pub webhooks: Vec<WebhookTrigger>,
}

#[derive(Debug, Clone, serde::Deserialize)]
pub struct ScriptTrigger {
    pub events: Vec<String>,  // Event types to trigger on
    pub script: String,       // Path to script or command
    pub timeout_ms: u64,      // Max execution time
    pub enabled: bool,
}

#[derive(Debug, Clone, serde::Deserialize)]
pub struct WebhookTrigger {
    pub events: Vec<String>,
    pub url: String,
    pub method: String,  // POST, PUT, GET
    pub headers: Option<Vec<(String, String)>>,
    pub timeout_ms: u64,
    pub enabled: bool,
}

impl EventHandler {
    pub fn new(config: EventConfig) -> Self {
        Self {
            config,
            last_volume_event: None,
            http_client: reqwest::Client::new(),
        }
    }

    pub async fn handle(&mut self, payload: EventPayload) {
        if !self.config.enabled {
            return;
        }

        // Debounce volume events
        if matches!(payload.event, DaemonEvent::VolumeChange { .. }) {
            if let Some(last) = self.last_volume_event {
                if last.elapsed() < Duration::from_millis(self.config.debounce_ms) {
                    return;  // Skip, too soon
                }
            }
            self.last_volume_event = Some(Instant::now());
        }

        let event_type = payload.event_type();

        // Run scripts
        for trigger in &self.config.scripts {
            if trigger.enabled && trigger.events.contains(&event_type) {
                self.run_script(trigger, &payload).await;
            }
        }

        // Call webhooks
        for trigger in &self.config.webhooks {
            if trigger.enabled && trigger.events.contains(&event_type) {
                self.call_webhook(trigger, &payload).await;
            }
        }
    }

    async fn run_script(&self, trigger: &ScriptTrigger, payload: &EventPayload) {
        let env_vars = payload.to_env_vars();
        let json = payload.to_json();

        let result = tokio::task::spawn_blocking({
            let script = trigger.script.clone();
            let timeout_ms = trigger.timeout_ms;
            move || {
                let mut cmd = if cfg!(windows) {
                    let mut c = Command::new("cmd");
                    c.args(["/C", &script]);
                    c
                } else {
                    let mut c = Command::new("sh");
                    c.args(["-c", &script]);
                    c
                };

                // Set environment variables
                for (key, value) in env_vars {
                    cmd.env(&key, &value);
                }
                cmd.env("DIAL_EVENT_JSON", &json);

                // Run with timeout
                let start = Instant::now();
                match cmd.output() {
                    Ok(output) => {
                        if start.elapsed() > Duration::from_millis(timeout_ms) {
                            log::warn!("Script {} timed out", script);
                        }
                        if !output.status.success() {
                            log::warn!(
                                "Script {} failed: {}",
                                script,
                                String::from_utf8_lossy(&output.stderr)
                            );
                        }
                    }
                    Err(e) => {
                        log::error!("Failed to run script {}: {}", script, e);
                    }
                }
            }
        });

        let _ = result.await;
    }

    async fn call_webhook(&self, trigger: &WebhookTrigger, payload: &EventPayload) {
        let method = match trigger.method.to_uppercase().as_str() {
            "GET" => reqwest::Method::GET,
            "PUT" => reqwest::Method::PUT,
            _ => reqwest::Method::POST,
        };

        let mut request = self.http_client
            .request(method, &trigger.url)
            .header("Content-Type", "application/json")
            .body(payload.to_json())
            .timeout(Duration::from_millis(trigger.timeout_ms));

        if let Some(headers) = &trigger.headers {
            for (key, value) in headers {
                request = request.header(key, value);
            }
        }

        match request.send().await {
            Ok(response) => {
                if !response.status().is_success() {
                    log::warn!(
                        "Webhook {} returned {}", 
                        trigger.url, 
                        response.status()
                    );
                }
            }
            Err(e) => {
                log::error!("Webhook {} failed: {}", trigger.url, e);
            }
        }
    }
}
