### Example Scripts

```bash
#!/bin/bash
# ~/.config/surface-dial/scripts/volume_light.sh
# Adjust smart lights based on volume

# Environment variables available:
# DIAL_EVENT_TYPE, DIAL_OLD_VOLUME, DIAL_NEW_VOLUME, DIAL_MODE, etc.

if [ "$DIAL_NEW_VOLUME" -gt 80 ]; then
    # High volume = dim lights for movie mode
    curl -X PUT "http://hue-bridge/api/lights/1/state" \
        -d '{"bri": 50}'
elif [ "$DIAL_NEW_VOLUME" -lt 20 ]; then
    # Low volume = bright lights
    curl -X PUT "http://hue-bridge/api/lights/1/state" \
        -d '{"bri": 254}'
fi
