 {"id":"DIAL-l6g","title":"Refactor daemon loop to use platform abstraction and config","description":"# Description

Refactor the main daemon HID event loop to use the platform abstraction module, integrate with config system, and provide hooks for all features.

## Current State

The existing `src/main.rs` has:
- Direct osascript calls for volume control
- Hardcoded timing constants
- Monolithic event loop
- No feature integration points

## Target State

- Event loop uses `Platform` trait for all OS operations
- All timing values read from Config
- Clean separation: `src/daemon.rs` for event loop, `src/main.rs` for CLI entry
- Integration hooks for: OSD, battery, volume curves, sensitivity, media control, device switching, webhooks, audio feedback, system tray
- Logging integrated throughout
- Hot config reload support
- Graceful shutdown with cleanup

## Implementation

### 1. Daemon Structure

```rust
// src/daemon.rs
use crate::config::Config;
use crate::platform::{CurrentPlatform, Platform, PlatformResult};
use crate::input::{ClickDetector, ClickResult, SensitivityConfig};
use crate::audio::{VolumeCurve, AudioFeedback};
use crate::osd::OsdOverlay;
use crate::battery::BatteryMonitor;
use crate::events::EventHandler;
use crate::tray::SystemTray;

use log::{info, warn, error, debug};
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use std::time::{Duration, Instant};

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ControlMode {
    Volume,
    Microphone,
}

pub struct Daemon {
    // Core state
    config: Config,
    platform: CurrentPlatform,
    running: Arc<AtomicBool>,

    // Control state
    control_mode: ControlMode,
    mic_mode_started: Option<Instant>,
    device_switching_mode: bool,
    selected_device_idx: usize,

    // Input processing
    click_detector: ClickDetector,
    sensitivity: SensitivityConfig,
    last_rotation: Option<Instant>,

    // Feature integrations (all optional based on config)
    volume_curve: Box<dyn VolumeCurve + Send>,
    mic_curve: Box<dyn VolumeCurve + Send>,
    osd: Option<OsdOverlay>,
    battery_monitor: Option<BatteryMonitor>,
    audio_feedback: Option<AudioFeedback>,
    event_handler: Option<EventHandler>,
    tray: Option<SystemTray>,

    // Statistics
    stats: DaemonStats,
}

#[derive(Debug, Default)]
pub struct DaemonStats {
    pub start_time: Option<Instant>,
    pub rotation_count: u64,
    pub click_count: u64,
    pub mode_switches: u64,
    pub device_switches: u64,
}

impl Daemon {
    pub fn new(config: Config) -> Self {
        let platform = CurrentPlatform::new();

        // Initialize volume curves based on config
        let volume_curve = Self::create_volume_curve(&config.volume);
        let mic_curve = Self::create_volume_curve_for_mic(&config.microphone);

        // Initialize click detector
        let click_config = crate::input::ClickConfig {
            double_click_ms: config.interaction.double_click_ms,
            triple_click_ms: config.interaction.triple_click_ms,
            long_press_ms: config.interaction.long_press_ms,
        };
        let click_detector = ClickDetector::new(click_config);

        // Initialize sensitivity
        let sensitivity = SensitivityConfig {
            dead_zone: config.sensitivity.dead_zone,
            multiplier: config.sensitivity.multiplier,
            invert: config.sensitivity.invert,
            accumulated: 0,
        };

        // Initialize optional features
        let osd = if config.osd.enabled {
            OsdOverlay::new(&config.osd).ok()
        } else {
            None
        };

        let battery_monitor = if config.battery.enabled {
            BatteryMonitor::new(&config.battery).ok()
        } else {
            None
        };

        let audio_feedback = if config.audio_feedback.enabled {
            AudioFeedback::new(&config.audio_feedback).ok()
        } else {
            None
        };

        let event_handler = if config.events.enabled {
            Some(EventHandler::new(config.events.clone()))
        } else {
            None
        };

        let tray = if config.tray.enabled {
            SystemTray::new(&config.tray).ok()
        } else {
            None
        };

        Self {
            config,
            platform,
            running: Arc::new(AtomicBool::new(false)),
            control_mode: ControlMode::Volume,
            mic_mode_started: None,
            device_switching_mode: false,
            selected_device_idx: 0,
            click_detector,
            sensitivity,
            last_rotation: None,
            volume_curve,
            mic_curve,
            osd,
            battery_monitor,
            audio_feedback,
            event_handler,
            tray,
            stats: DaemonStats::default(),
        }
    }

    fn create_volume_curve(config: &crate::config::VolumeConfig) -> Box<dyn VolumeCurve + Send> {
        match config.curve.as_str() {
            "linear" => Box::new(crate::audio::LinearCurve),
            "logarithmic" => Box::new(crate::audio::LogarithmicCurve::new(config.curve_steepness)),
            "exponential" => Box::new(crate::audio::ExponentialCurve::default()),
            "custom" => Box::new(crate::audio::CustomCurve::new(config.custom_curve_points.clone())),
            _ => Box::new(crate::audio::LogarithmicCurve::default()),
        }
    }

    fn create_volume_curve_for_mic(config: &crate::config::MicrophoneConfig) -> Box<dyn VolumeCurve + Send> {
        // Mic typically uses linear
        Box::new(crate::audio::LinearCurve)
    }

    pub fn running(&self) -> Arc<AtomicBool> {
        self.running.clone()
    }

    pub fn run(&mut self) {
        self.running.store(true, Ordering::SeqCst);
        self.stats.start_time = Some(Instant::now());

        info!("Daemon starting...");
        info!("Config: volume curve={}, OSD={}, battery={}, tray={}",
            self.config.volume.curve,
            self.config.osd.enabled,
            self.config.battery.enabled,
            self.config.tray.enabled
        );

        // Fire daemon start event
        self.fire_event(crate::events::DaemonEvent::DaemonStart);

        // Update tray on start
        self.update_tray();

        // Main loop
        while self.running.load(Ordering::SeqCst) {
            self.tick();
            self.process_hid_events();

            // Small sleep to prevent busy-waiting
            std::thread::sleep(Duration::from_millis(1));
        }

        // Cleanup
        self.fire_event(crate::events::DaemonEvent::DaemonStop);
        info!("Daemon stopped. Stats: rotations={}, clicks={}", 
            self.stats.rotation_count, 
            self.stats.click_count
        );
    }

    fn tick(&mut self) {
        let now = Instant::now();

        // Check mic mode expiry
        if self.control_mode == ControlMode::Microphone {
            if let Some(started) = self.mic_mode_started {
                let duration = Duration::from_secs(self.config.microphone.mode_duration as u64);
                if started.elapsed() >= duration {
                    info!("Mic mode expired, returning to volume control");
                    self.switch_mode(ControlMode::Volume);
                    self.mic_mode_started = None;
                }
            }
        }

        // Process click detector timeouts
        let click_result = self.click_detector.tick();
        self.process_click_result(click_result);

        // Check battery periodically
        if let Some(ref mut monitor) = self.battery_monitor {
            if monitor.should_check() {
                if let Ok(status) = monitor.read_battery() {
                    // Check for low battery notifications
                    if let Some(notification) = monitor.check_thresholds(&status) {
                        self.platform.send_notification(
                            &notification.title,
                            &notification.body,
                            notification.urgency,
                        ).ok();
                    }

                    // Update tray if battery changed significantly
                    self.update_tray();
                }
            }
        }

        // Update OSD auto-hide
        if let Some(ref mut osd) = self.osd {
            osd.tick();
        }
    }

    fn process_hid_events(&mut self) {
        // HID device handling moved to separate module
        // This is called from the main loop

        // TODO: Read from HID device
        // For now, this is a placeholder showing the integration pattern
    }

    pub fn handle_button_down(&mut self) {
        let result = self.click_detector.button_down();
        self.process_click_result(result);
    }

    pub fn handle_button_up(&mut self) {
        let result = self.click_detector.button_up();
        self.process_click_result(result);
    }

    pub fn handle_rotation(&mut self, raw_rotation: i8) {
        // Check for device switching mode (long-press + rotate)
        if self.device_switching_mode {
            self.handle_device_switch_rotation(raw_rotation);
            return;
        }

        // Apply sensitivity/dead zone
        let adjusted = match self.sensitivity.process(raw_rotation) {
            Some(v) => v,
            None => return, // Within dead zone
        };

        // Get current volume and curve based on mode
        let (get_vol, set_vol, curve, min_step, max_step) = match self.control_mode {
            ControlMode::Volume => (
                |p: &CurrentPlatform| p.get_volume(),
                |p: &CurrentPlatform, v| p.set_volume(v),
                &*self.volume_curve,
                self.config.volume.step_min,
                self.config.volume.step_max,
            ),
            ControlMode::Microphone => {
                self.mic_mode_started = Some(Instant::now()); // Reset timer
                (
                    |p: &CurrentPlatform| p.get_mic_volume(),
                    |p: &CurrentPlatform, v| p.set_mic_volume(v),
                    &*self.mic_curve,
                    self.config.microphone.step_min,
                    self.config.microphone.step_max,
                )
            }
        };

        if let Ok(current_actual) = get_vol(&self.platform) {
            // Convert actual volume to dial position using curve inverse
            let current_dial = curve.inverse(current_actual);

            // Calculate step based on rotation speed
            let step = self.calculate_step(min_step, max_step);

            // Apply rotation to dial position
            let direction = adjusted.signum();
            let new_dial = (current_dial + direction * step).clamp(0, 100);

            // Convert back to actual volume using curve
            let new_actual = curve.apply(new_dial);

            if new_actual != current_actual {
                if let Err(e) = set_vol(&self.platform, new_actual) {
                    error!("Failed to set volume: {}", e);
                } else {
                    debug!("Volume: {}% (dial: {}%)", new_actual, new_dial);

                    // Update OSD
                    if let Some(ref mut osd) = self.osd {
                        osd.show_volume(new_actual, self.control_mode);
                    }

                    // Play audio feedback
                    if let Some(ref feedback) = self.audio_feedback {
                        if new_actual == 0 || new_actual == 100 {
                            feedback.boundary();
                        } else {
                            feedback.tick();
                        }
                    }

                    // Fire event
                    self.fire_event(crate::events::DaemonEvent::VolumeChange {
                        old_volume: current_actual,
                        new_volume: new_actual,
                        mode: match self.control_mode {
                            ControlMode::Volume => "volume",
                            ControlMode::Microphone => "microphone",
                        }.to_string(),
                    });

                    // Update tray tooltip
                    self.update_tray();
                }
            }
        }

        self.last_rotation = Some(Instant::now());
        self.stats.rotation_count += 1;
    }

    fn process_click_result(&mut self, result: ClickResult) {
        match result {
            ClickResult::SingleClick => {
                info!("Single click: toggle mute");
                self.handle_mute_toggle();
                self.stats.click_count += 1;
            }
            ClickResult::DoubleClick => {
                info!("Double click: switch to mic mode");
                self.switch_mode(ControlMode::Microphone);
                self.mic_mode_started = Some(Instant::now());
                self.stats.click_count += 1;
            }
            ClickResult::TripleClick => {
                if self.config.media_control.enabled {
                    info!("Triple click: media play/pause");
                    self.handle_media_control();
                }
                self.stats.click_count += 1;
            }
            ClickResult::LongPressStart => {
                if self.config.device_switching.enabled {
                    info!("Long press: entering device switching mode");
                    self.device_switching_mode = true;
                    self.show_device_picker();
                } else {
                    info!("Long press: F15 down");
                    self.platform.send_key_down(crate::platform::Key::F15).ok();
                }
            }
            ClickResult::LongPressEnd => {
                if self.device_switching_mode {
                    info!("Long press release: confirming device selection");
                    self.confirm_device_selection();
                    self.device_switching_mode = false;
                } else {
                    info!("Long press release: F15 up");
                    self.platform.send_key_up(crate::platform::Key::F15).ok();
                }
            }
            ClickResult::None => {}
        }
    }

    fn handle_mute_toggle(&mut self) {
        let result = match self.control_mode {
            ControlMode::Volume => self.platform.toggle_mute(),
            ControlMode::Microphone => self.platform.toggle_mic_mute(),
        };

        if let Err(e) = result {
            error!("Failed to toggle mute: {}", e);
        } else {
            // Get mute state for OSD
            let muted = match self.control_mode {
                ControlMode::Volume => self.platform.is_muted().unwrap_or(false),
                ControlMode::Microphone => self.platform.is_mic_muted().unwrap_or(false),
            };

            if let Some(ref mut osd) = self.osd {
                osd.show_mute(muted, self.control_mode);
            }

            if let Some(ref feedback) = self.audio_feedback {
                feedback.mute_toggle();
            }

            self.fire_event(crate::events::DaemonEvent::MuteToggle {
                muted,
                mode: match self.control_mode {
                    ControlMode::Volume => "volume",
                    ControlMode::Microphone => "microphone",
                }.to_string(),
            });

            self.update_tray();
        }
    }

    fn switch_mode(&mut self, new_mode: ControlMode) {
        let old_mode = self.control_mode;
        self.control_mode = new_mode;
        self.sensitivity.reset(); // Reset dead zone accumulator

        if let Some(ref mut osd) = self.osd {
            osd.show_mode_change(new_mode);
        }

        if let Some(ref feedback) = self.audio_feedback {
            feedback.mode_change();
        }

        self.fire_event(crate::events::DaemonEvent::ModeChange {
            old_mode: format!("{:?}", old_mode).to_lowercase(),
            new_mode: format!("{:?}", new_mode).to_lowercase(),
        });

        self.update_tray();
        self.stats.mode_switches += 1;
    }

    fn handle_media_control(&mut self) {
        let action = match self.config.media_control.triple_click_action.as_str() {
            "play_pause" => crate::platform::MediaKey::PlayPause,
            "next_track" => crate::platform::MediaKey::NextTrack,
            "prev_track" => crate::platform::MediaKey::PrevTrack,
            _ => crate::platform::MediaKey::PlayPause,
        };

        if let Err(e) = self.platform.send_media_key(action) {
            error!("Failed to send media key: {}", e);
        } else {
            if let Some(ref mut osd) = self.osd {
                osd.show_media_action("⏯ Play/Pause");
            }

            self.fire_event(crate::events::DaemonEvent::MediaControl {
                action: self.config.media_control.triple_click_action.clone(),
            });
        }
    }

    fn show_device_picker(&mut self) {
        if let Ok(devices) = self.platform.list_output_devices() {
            self.selected_device_idx = devices.iter()
                .position(|d| d.is_default)
                .unwrap_or(0);

            if let Some(ref mut osd) = self.osd {
                osd.show_device_picker(&devices, self.selected_device_idx);
            }
        }
    }

    fn handle_device_switch_rotation(&mut self, direction: i8) {
        if let Ok(devices) = self.platform.list_output_devices() {
            let len = devices.len();
            if len == 0 { return; }

            if direction > 0 {
                self.selected_device_idx = (self.selected_device_idx + 1) % len;
            } else {
                self.selected_device_idx = (self.selected_device_idx + len - 1) % len;
            }

            if let Some(ref mut osd) = self.osd {
                osd.show_device_picker(&devices, self.selected_device_idx);
            }
        }
    }

    fn confirm_device_selection(&mut self) {
        if let Ok(devices) = self.platform.list_output_devices() {
            if let Some(device) = devices.get(self.selected_device_idx) {
                match self.platform.set_default_output(&device.id) {
                    Ok(()) => {
                        info!("Switched to: {}", device.name);

                        if let Some(ref mut osd) = self.osd {
                            osd.show_device_confirmed(&device.name);
                        }

                        self.fire_event(crate::events::DaemonEvent::DeviceSwitch {
                            old_device: "".to_string(), // Could track this
                            new_device: device.name.clone(),
                        });

                        self.update_tray();
                        self.stats.device_switches += 1;
                    }
                    Err(e) => error!("Failed to switch device: {}", e),
                }
            }
        }
    }

    fn calculate_step(&self, min_step: i32, max_step: i32) -> i32 {
        let Some(last) = self.last_rotation else {
            return min_step;
        };

        let elapsed_ms = last.elapsed().as_millis() as u64;
        let fast_ms = self.config.acceleration.fast_ms;
        let slow_ms = self.config.acceleration.slow_ms;

        if elapsed_ms <= fast_ms {
            max_step
        } else if elapsed_ms >= slow_ms {
            min_step
        } else {
            let range = slow_ms - fast_ms;
            let pos = elapsed_ms - fast_ms;
            let ratio = 1.0 - (pos as f32 / range as f32);
            let step_range = (max_step - min_step) as f32;
            min_step + (ratio * step_range) as i32
        }
    }

    fn fire_event(&self, event: crate::events::DaemonEvent) {
        if let Some(ref handler) = self.event_handler {
            let payload = crate::events::EventPayload::new(event);
            // Fire async
            let handler = handler.clone();
            std::thread::spawn(move || {
                tokio::runtime::Runtime::new()
                    .unwrap()
                    .block_on(handler.handle(payload));
            });
        }
    }

    fn update_tray(&mut self) {
        if let Some(ref mut tray) = self.tray {
            let volume = self.platform.get_volume().unwrap_or(0);
            let muted = self.platform.is_muted().unwrap_or(false);
            let battery = self.battery_monitor.as_ref()
                .and_then(|m| m.last_status());

            tray.update(volume, muted, self.control_mode, battery);
        }
    }

    /// Reload configuration (for hot reload)
    pub fn reload_config(&mut self, new_config: Config) {
        info!("Reloading configuration...");

        // Update curves
        self.volume_curve = Self::create_volume_curve(&new_config.volume);
        self.mic_curve = Self::create_volume_curve_for_mic(&new_config.microphone);

        // Update click detector
        self.click_detector.update_config(crate::input::ClickConfig {
            double_click_ms: new_config.interaction.double_click_ms,
            triple_click_ms: new_config.interaction.triple_click_ms,
            long_press_ms: new_config.interaction.long_press_ms,
        });

        // Update sensitivity
        self.sensitivity = SensitivityConfig {
            dead_zone: new_config.sensitivity.dead_zone,
            multiplier: new_config.sensitivity.multiplier,
            invert: new_config.sensitivity.invert,
            accumulated: 0,
        };

        // Toggle features on/off
        if new_config.osd.enabled && self.osd.is_none() {
            self.osd = OsdOverlay::new(&new_config.osd).ok();
        } else if !new_config.osd.enabled {
            self.osd = None;
        }

        // Similar for other features...

        self.config = new_config;
        info!("Configuration reloaded");
    }
}
