Create a configuration file system that stores settings in platform-appropriate locations.

## Config File Locations

```
macOS:   ~/Library/Application Support/surface-dial/config.toml
Linux:   ~/.config/surface-dial/config.toml
Windows: %APPDATA%\surface-dial\config.toml
```

Use the `dirs` crate to get these paths.

## Config Schema (TOML)

```toml
# ~/.config/surface-dial/config.toml

[volume]
step_min = 2          # Slow rotation step (1-20)
step_max = 8          # Fast rotation step (1-20)
curve = "logarithmic" # linear, logarithmic, exponential, custom
curve_steepness = 9.0 # For log/exp curves (1.0-20.0)

# Custom curve points (only used if curve = "custom")
# Format: [[dial_position, actual_volume], ...]
custom_curve_points = [
    [0, 0],
    [25, 10],
    [50, 35],
    [75, 65],
    [100, 100],
]

[microphone]
step_min = 3          # Slow rotation step (1-20)
step_max = 10         # Fast rotation step (1-20)
mode_duration = 10    # Seconds before returning to volume mode
curve = "linear"      # Mic often works better linear

[acceleration]
fast_ms = 80          # Below this = max step
slow_ms = 400         # Above this = min step

[interaction]
double_click_ms = 400   # Max time between clicks for double-click
triple_click_ms = 600   # Max time for triple-click (from first click)
long_press_ms = 1000    # Hold duration to trigger F15

[sensitivity]
dead_zone = 0           # 0-10, rotation units to ignore
multiplier = 1.0        # 0.1-5.0, sensitivity scale
invert = false          # Reverse rotation direction (for left-handed)

[osd]
enabled = true          # Enable/disable OSD
position = "center-bottom"  # center-bottom, center, top-right, etc.
size = "medium"         # small, medium, large
timeout_ms = 1500       # Auto-hide delay
opacity = 0.85          # Background opacity (0.0-1.0)
show_icon = true        # Show volume/mic emoji
show_percentage = true  # Show numeric percentage

[battery]
enabled = true                    # Enable battery monitoring
poll_interval_seconds = 300       # Check every 5 minutes
warning_thresholds = [20, 10, 5]  # Notify at these percentages
show_in_status = true             # Include in status command
show_in_osd = true                # Show battery icon in OSD

[device_switching]
enabled = true                   # Enable device switching feature
mode = "long_press_rotate"       # Trigger mode
show_in_osd = true               # Show device picker in OSD

[media_control]
enabled = true                  # Enable triple-click media control
triple_click_action = "play_pause"  # play_pause, next_track, or custom

[audio_feedback]
enabled = false             # Disabled by default (can be annoying)
volume = 0.3                # Feedback sound volume (0.0-1.0)
tick = true                 # Play on each volume step
boundary = true             # Play when hitting 0% or 100%
mode_change = true          # Play on mode switch
mute = true                 # Play on mute toggle

[events]
enabled = false             # Event hooks disabled by default
debounce_ms = 500           # Don't fire volume events more than 2x/sec

# Example script trigger (uncomment to use)
# [[events.scripts]]
# events = ["volume_change"]
# script = "~/.config/surface-dial/scripts/volume_light.sh"
# timeout_ms = 5000
# enabled = true

[tray]
enabled = true              # Enable system tray icon
show_volume = true          # Show volume in tooltip
show_battery = true         # Show battery in tooltip
show_mode = true            # Show mode indicator

[daemon]
log_level = "info"          # error, warn, info, debug, trace
log_file_enabled = true     # Write logs to file
log_max_size_mb = 10        # Max log file size before rotation
