## Rust Implementation

```rust
// src/config.rs
use serde::{Deserialize, Serialize};
use std::path::PathBuf;

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
#[serde(default)]
pub struct Config {
    pub volume: VolumeConfig,
    pub microphone: MicrophoneConfig,
    pub acceleration: AccelerationConfig,
    pub interaction: InteractionConfig,
    pub sensitivity: SensitivityConfig,
    pub osd: OsdConfig,
    pub battery: BatteryConfig,
    pub device_switching: DeviceSwitchingConfig,
    pub media_control: MediaControlConfig,
    pub audio_feedback: AudioFeedbackConfig,
    pub events: EventsConfig,
    pub tray: TrayConfig,
    pub daemon: DaemonConfig,
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
#[serde(default)]
pub struct VolumeConfig {
    pub step_min: i32,
    pub step_max: i32,
    pub curve: String,
    pub curve_steepness: f64,
    pub custom_curve_points: Vec<(i32, i32)>,
}

impl Default for VolumeConfig {
    fn default() -> Self {
        Self {
            step_min: 2,
            step_max: 8,
            curve: "logarithmic".into(),
            curve_steepness: 9.0,
            custom_curve_points: vec![],
        }
    }
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
#[serde(default)]
pub struct SensitivityConfig {
    pub dead_zone: u8,
    pub multiplier: f32,
    pub invert: bool,
}

impl Default for SensitivityConfig {
    fn default() -> Self {
        Self {
            dead_zone: 0,
            multiplier: 1.0,
            invert: false,
        }
    }
}

// ... (similar structs for all config sections)

impl Config {
    pub fn path() -> PathBuf {
        dirs::config_dir()
            .unwrap_or_else(|| PathBuf::from("."))
            .join("surface-dial")
            .join("config.toml")
    }

    pub fn load() -> Self {
        Self::load_from(&Self::path()).unwrap_or_default()
    }

    pub fn load_from(path: &PathBuf) -> Result<Self, ConfigError> {
        if !path.exists() {
            return Ok(Self::default());
        }
        let contents = std::fs::read_to_string(path)?;
        let config: Config = toml::from_str(&contents)?;
        config.validate()?;
        Ok(config)
    }

    pub fn save(&self) -> Result<(), ConfigError> {
        self.save_to(&Self::path())
    }

    pub fn save_to(&self, path: &PathBuf) -> Result<(), ConfigError> {
        if let Some(parent) = path.parent() {
            std::fs::create_dir_all(parent)?;
        }
        let contents = toml::to_string_pretty(self)?;
        std::fs::write(path, contents)?;
        Ok(())
    }

    pub fn validate(&self) -> Result<(), ConfigError> {
        // Step validation
        if self.volume.step_min < 1 || self.volume.step_min > 20 {
            return Err(ConfigError::Validation("volume.step_min must be 1-20".into()));
        }
        if self.volume.step_max < self.volume.step_min {
            return Err(ConfigError::Validation("volume.step_max must be >= step_min".into()));
        }
        // ... more validations
        Ok(())
    }

    /// Get a config value by dot-notation key
    pub fn get(&self, key: &str) -> Option<String> {
        match key {
            "volume.step_min" => Some(self.volume.step_min.to_string()),
            "volume.step_max" => Some(self.volume.step_max.to_string()),
            "volume.curve" => Some(self.volume.curve.clone()),
            "sensitivity.dead_zone" => Some(self.sensitivity.dead_zone.to_string()),
            "sensitivity.multiplier" => Some(self.sensitivity.multiplier.to_string()),
            "sensitivity.invert" => Some(self.sensitivity.invert.to_string()),
            "osd.enabled" => Some(self.osd.enabled.to_string()),
            "osd.timeout_ms" => Some(self.osd.timeout_ms.to_string()),
            "battery.enabled" => Some(self.battery.enabled.to_string()),
            // ... all keys
            _ => None,
        }
    }

    /// Set a config value by dot-notation key
    pub fn set(&mut self, key: &str, value: &str) -> Result<(), ConfigError> {
        match key {
            "volume.step_min" => {
                self.volume.step_min = value.parse()
                    .map_err(|_| ConfigError::Parse("Invalid integer".into()))?;
            }
            "volume.step_max" => {
                self.volume.step_max = value.parse()
                    .map_err(|_| ConfigError::Parse("Invalid integer".into()))?;
            }
            "volume.curve" => {
                if !["linear", "logarithmic", "exponential", "custom"].contains(&value) {
                    return Err(ConfigError::Validation("Invalid curve type".into()));
                }
                self.volume.curve = value.to_string();
            }
            "sensitivity.invert" => {
                self.sensitivity.invert = value.parse()
                    .map_err(|_| ConfigError::Parse("Invalid boolean".into()))?;
            }
            "osd.enabled" => {
                self.osd.enabled = value.parse()
                    .map_err(|_| ConfigError::Parse("Invalid boolean".into()))?;
            }
            // ... all keys
            _ => return Err(ConfigError::UnknownKey(key.to_string())),
        }
        self.validate()
    }

    /// Reset config to defaults
    pub fn reset(&mut self) {
        *self = Self::default();
    }

    /// List all config keys (for CLI completion)
    pub fn keys() -> Vec<&'static str> {
        vec![
            "volume.step_min", "volume.step_max", "volume.curve",
            "microphone.step_min", "microphone.step_max", "microphone.mode_duration",
            "sensitivity.dead_zone", "sensitivity.multiplier", "sensitivity.invert",
            "osd.enabled", "osd.position", "osd.timeout_ms",
            "battery.enabled", "battery.poll_interval_seconds",
            "tray.enabled",
            "daemon.log_level",
            // ... all keys
        ]
    }
}

#[derive(Debug, thiserror::Error)]
pub enum ConfigError {
    #[error("IO error: {0}")]
    Io(#[from] std::io::Error),
    #[error("Parse error: {0}")]
    Parse(String),
    #[error("TOML error: {0}")]
    Toml(#[from] toml::de::Error),
    #[error("Validation error: {0}")]
    Validation(String),
    #[error("Unknown key: {0}")]
    UnknownKey(String),
}
```

## Hot Reload Support

```rust
impl Config {
    /// Watch for config file changes and reload
    pub fn watch_changes(callback: impl Fn(Config) + Send + 'static) {
        use notify::{Watcher, RecursiveMode, watcher};
        use std::sync::mpsc::channel;
        use std::time::Duration;

        let (tx, rx) = channel();
        let mut watcher = watcher(tx, Duration::from_secs(2)).unwrap();

        let config_path = Self::path();
        if let Some(parent) = config_path.parent() {
            watcher.watch(parent, RecursiveMode::NonRecursive).ok();
        }

        std::thread::spawn(move || {
            loop {
                if rx.recv().is_ok() {
                    if let Ok(config) = Self::load_from(&Self::path()) {
                        callback(config);
                    }
                }
            }
        });
    }
}
```

## Validation Rules

- All numeric values must be positive
- step_min <= step_max
- All durations in valid ranges (10-5000ms)
- log_level must be valid
- curve must be one of: linear, logarithmic, exponential, custom
- curve_steepness must be 1.0-20.0
- sensitivity.multiplier must be 0.1-5.0
- sensitivity.dead_zone must be 0-10
- opacity must be 0.0-1.0

