### Daemon Integration

```rust
// In src/daemon.rs

impl Daemon {
    fn process_click_result(&mut self, result: ClickResult) {
        match result {
            ClickResult::SingleClick => {
                match self.control_mode {
                    ControlMode::Volume => CurrentPlatform::toggle_mute(),
                    ControlMode::Microphone => CurrentPlatform::toggle_mic_mute(),
                }
            }
            ClickResult::DoubleClick => {
                info!("Double-click: Mic mode for 10 seconds");
                self.control_mode = ControlMode::Microphone;
                self.mic_mode_started = Some(Instant::now());
                EventLog::log(EventType::ModeChange {
                    from: ControlMode::Volume,
                    to: ControlMode::Microphone,
                });
            }
            ClickResult::TripleClick => {
                info!("Triple-click: Play/Pause");
                CurrentPlatform::send_play_pause();
                EventLog::log(EventType::MediaControl {
                    action: "play_pause",
                });
                if let Some(osd) = &mut self.osd {
                    osd.show_media_action("⏯ Play/Pause");
                }
            }
            ClickResult::LongPressStart => {
                CurrentPlatform::send_key_down(Key::F15);
            }
            ClickResult::LongPressEnd => {
                CurrentPlatform::send_key_up(Key::F15);
            }
            ClickResult::None => {}
        }
    }
}
